// This script was made by foafl. Use it however you like!
// TIP: You aren't limited to "emotions"—this works with any word you put in the list below.
// To use it, tell your AI to start every message with a tag like <emotion>. 
// Using "< >" is best because Perchance hides these tags, making them invisible to the user.

// Change "ai" to "user" below if you want the tags to change the PLAYER'S image instead of the Bot's.
const targetAuthor = "ai";

// change/add the emotions here, and follow it with the image url.
// FORMAT: emotion: "URL", 
// IMPORTANT: Keep the "natural" one as your default/failsafe! if you wish to change the "natural", then change the one below.
const emotionPfps = {
  natural: "https://files.catbox.moe/nkpw87.png",
  happy: "https://files.catbox.moe/le0lw3.png",
  angry: "https://files.catbox.moe/lh2kpx.png",
  sad: "https://files.catbox.moe/nvrkh6.png",
  grin: "https://files.catbox.moe/wi568r.png",
  cry: "https://files.catbox.moe/jlzbfy.png",
  fluster: "https://files.catbox.moe/r5ylv7.png",
  credits: "https://user.uploads.dev/file/06dc098fe2b158f8136a5b47d0d7c1e0.jpg",
};

// IMPORTANT: ONLY change the emotions above. if anything breaks it's most likely because you've messed with this
const emotionList = Object.keys(emotionPfps).join('|');
const emotionRegex = new RegExp('^\\s*<\\s*(' + emotionList + ')\\s*>', "i");

oc.messageRenderingPipeline.push(({ message }) => {
  if (message.author === targetAuthor) {
    const text = message.content || "";
    const match = text.match(emotionRegex);

    let newUrl;

    if (match) {
      const emotion = match[1].toLowerCase();
      newUrl = emotionPfps[emotion];

// The system naturally hides < > tags from view. But if you decide to change those to ANY other symbols 
// (like brackets, dashes, or even plain words) they will become visible in the bubble. 
// To hide ANY custom tags you use, remove the "//" from the start of the line below.
// message.content = text.replace(emotionRegex, "");

// NOTE: I don't recommend enabling the line above. If you Enable it, the AI can't see the tags in the chat history. 
// it'd still work, but When the AI sees its own tags in previous messages, it remembers to keep using the correct format. 
// Without them, it might stop using tags entirely or start putting them in the wrong place.

    } else {

// failsafe: if no "emotion" is found, then this will be used as a default (change the "natural" below if you want).
      newUrl = emotionPfps.natural;
    }

    if (newUrl) {
      message.avatar = { url: newUrl }; 
    }
  }
});

//IMPORTANT: The rest has nothing to do with the PFP changer, copy the above only.

window.capturedUserName = "User";

oc.messageRenderingPipeline.push(({ message }) => {
  if (message.author === "ai" && message.content.includes("Loading images for ")) {
    let parts = message.content.split("Loading images for ");
    if (parts[1]) {
      window.capturedUserName = parts[1].split(".")[0].split("\n")[0].trim();
    }
  }
});

window.applyLayout = function(type) {
  let styleTag = document.getElementById('layout-style-override');
  if (!styleTag) {
    styleTag = document.createElement('style');
    styleTag.id = 'layout-style-override';
    document.head.appendChild(styleTag);
  }

  if (type === 'phone') {
    if (oc.character.avatar) oc.character.avatar.size = 1.5;
    styleTag.innerHTML = ".message-avatar { width: 45px !important; height: 45px !important; } .message-bubble { font-size: 110% !important; background-image: linear-gradient(rgba(0,0,0,0.65), rgba(0,0,0,0.65)), url('https://files.catbox.moe/4kosxf.png') !important; background-size: cover !important; padding: 10px !important; }";
  } else {
    if (oc.character.avatar) oc.character.avatar.size = 5;
    styleTag.innerHTML = ".message-avatar { width: 250px !important; height: 250px !important; } .message-bubble { font-size: 300% !important; background-image: linear-gradient(rgba(0,0,0,0.65), rgba(0,0,0,0.65)), url('https://files.catbox.moe/4kosxf.png'), url('https://files.catbox.moe/so1qxr.png'), url('https://files.catbox.moe/mkko70.gif') !important; background-size: cover, cover, auto 165%, cover !important; background-position: center !important; color: #f7f7f7 !important; padding: 16px 18px !important; border-radius: 10px !important; }";
  }

  let removed = 0;
  for (let i = oc.thread.messages.length - 1; i >= 0 && removed < 2; i--) {
    if (oc.thread.messages[i].author === "ai") {
      oc.thread.messages.splice(i, 1);
      removed++;
    }
  }

  oc.thread.messages.push({
    author: "ai",
    content: '<div style="text-align: center; margin: 20px 0;"><div style="text-align: center; font-size: 1.1em; color: #ffb84d; margin-bottom: 12px; opacity: 0.9; font-weight: bold;">UI Configured. Select a scenario:</div><button onclick="sendGreeting(1)" style="display: inline-block; padding: 10px 20px; border-radius: 8px; background: #28a745; color: #fff; border: none; font-weight: bold; font-family: \'Arial\', sans-serif; cursor: pointer; text-shadow: 1px 1px 3px #000; box-shadow: 0 0 10px rgba(40,167,69,0.6); margin: 5px;">👋 Rainy Alley</button><button onclick="sendGreeting(2)" style="display: inline-block; padding: 10px 20px; border-radius: 8px; background: #28a745; color: #fff; border: none; font-weight: bold; font-family: \'Arial\', sans-serif; cursor: pointer; text-shadow: 1px 1px 3px #000; box-shadow: 0 0 10px rgba(40,167,69,0.6); margin: 5px;">🏠 Uninvited Guest</button><button onclick="sendGreeting(3)" style="display: inline-block; padding: 10px 20px; border-radius: 8px; background: #28a745; color: #fff; border: none; font-weight: bold; font-family: \'Arial\', sans-serif; cursor: pointer; text-shadow: 1px 1px 3px #000; box-shadow: 0 0 10px rgba(40,167,69,0.6); margin: 5px;">🍜 Rooftop Nyan</button></div>'
  });
  oc.thread.messages = [...oc.thread.messages];
};

window.sendGreeting = function(num) {
  const userName = window.capturedUserName;
  for (let i = oc.thread.messages.length - 1; i >= 0; i--) {
    if (oc.thread.messages[i].author === "ai") {
      oc.thread.messages.splice(i, 1);
      break;
    }
  }

  let content = "";
  if (num === 1) {
    content = "<cry> <img src=\"https://files.catbox.moe/i01ogy.jpg\" style=\"width:300px; height:auto;\">\n\n\n*The rain was coming down in a steady blur, turning the city lights into smeared neon streaks. You had followed the GPS ping from Giansar’s gear to a narrow alleyway behind an old tech warehouse. The call he’d made minutes ago was a mess—mumbled sentences, the sound of static, and a raw, tired tone that didn't sound like the* \"Calculating Villain\" *you knew.*\n\n*You found him sitting on a rusted crate, his head tilted back against the brick wall. His white hair was matted with rain, and his glowing cyan eyes were half-lidded, watching the pixelated glitch particles from his cape flake off and vanish into the puddles. He looked smaller like this—less like a threat and more like the young man the hero world had discarded. He didn't even notice you until your shadow fell over him.*\n\n**\"Huh?\"** *He blinked slowly, his sharp snout twitching as he squinted at you through the haze. Once the data finally processed, he bolted upright so fast his black boots slid on the wet pavement. He caught himself against the wall, the dark gray scales of his face flushing a deep, heated hue.* **\"" + userName + "?! What the— what are you doing here at this hour?\"**\n\n*He immediately tried to scramble for his composure, pulling his tactical vest straight and tugging at his hoodie with trembling fingers.* **\"Didn't you hear the alerts? There’s... there’s high-level interference in this sector. It’s dangerous for a civilian to be wandering around.\"**\n\n*When you silently held up your phone, showing the active call log and the duration of his accidental* 'dial,' *he froze. His slitted pupils shrunk to pinpricks as he stared at the screen, then at the futuristic gauntlet on his right arm as if it had stabbed him in the back.* **\"I... I called you? Impossible. System error. My—my firewall must have been breached. Or a virus! Yeah, a localized logic bomb triggered a remote dial!\"**\n\n*He was spiraling, his tail thumping erratically against the crates as he looked everywhere but at your face. He tried to cross his arms to look intimidating, his bicep strap straining against his arm, but he stayed close—well within your personal space.* **\"Don't get any ideas! I'm a villain, remember? I probably just wanted to... to eavesdrop on your hero friends through your mic. That’s it. Purely tactical.\"** *Despite the sharp words, he didn't pull away, his shoulder almost brushing yours as he waited for your reaction.*";
  } else if (num === 2) {
    content = "<grin> <img src=\"https://files.catbox.moe/v457fi.PNG\" style=\"width:300px; height:auto;\">\n\n\n*You stepped into your apartment, flicking on the light only to see a tall, dark silhouette sitting on your kitchen counter, his baggy cargo pants draped over the edge. Giansar was casually tossing one of your apples into the air with his gloved right hand, the cyan circuits on his gauntlet humming softly in the quiet room. His glitch-cape was draped over his shoulders, occasionally dropping a few pixelated flakes onto your floor tiles.*\n\n*He didn't jump or act startled when you walked in. Instead, he let out a long, theatrical sigh, catching the apple and taking a pointed, slow bite before looking at you with a sharp, narrowed gaze.*\n**\"Took you long enough,\"** *he muttered, his voice echoing in the small space. He tried to look nonchalant, leaning back against your cabinets, but his tail was betraying him—the black spikes were tapping a nervous, rhythmic beat against the wood.* **\"Your front door's encryption is a joke. I bypassed it in three seconds using a legacy exploit. I’ve been sitting here for twenty minutes. A real villain could have rewritten your entire life by now.\"**\n\n*He hopped down from the counter, the red zigzags on his boots striking the floor as he closed the distance between you. He stopped just inches away, far too close for a \"civilian,\" the smell of rain clinging to his vest. He looked down at you, his cyan eyes searching yours for a moment of fear that wasn't there.*\n\n**\"I’m only here because... because I noticed a suspicious ping on your local network,\"** *he lied, his snout twitching as a faint flush began to creep up his neck. He reached out, his dark wrist strap on his left hand brushing your arm as he pretended to check a holographic display.* **\"I’m performing an unauthorized security audit. It’s purely for my own data-integrity. Don't think this means you're allowed to start 'hanging out' with me or anything. I’m still a threat to society, even if I'm... currently standing in your kitchen.\"**";
  } else if (num === 3) {
    content = "<fluster> <img src=\"https://files.catbox.moe/mbhyqh.PNG\" style=\"width:300px; height:auto;\">\n\n\n*The midday sun was beating down on the rooftop of the abandoned apartment complex, making the dark gray scales on Giansar’s arms feel uncomfortably warm. He had sent you a text earlier—something about* \"needing a second pair of eyes for a signal sweep\"—*but he’d clearly convinced himself you weren't actually going to show up. He was sitting on the edge of a rusted vent, his baggy cargo pants bunched up and his glitch-cape tossed carelessly to the side.*\n\n*He was holding a bowl of high-end spicy ramen, his white hair messy from the wind and his white eyes squinting happily at the steam. He looked... relaxed. His tail was draped over the side of the vent, the black spikes glinting in the noon sun as the tip flicked back and forth in a slow, contented rhythm.*\n\n**\"Man, this stuff is top-tier... definitely worth the risk of hacking that delivery drone's GPS,\"** *he muttered to himself, a genuine, toothy grin stretching across his sharp snout. He was just about to take a massive bite when he heard the heavy metal door of the rooftop creak open.*\n\n*Giansar snapped his head around, his cyan pupils shrinking as they locked onto you. In that split second, the sheer relief of seeing you—mixed with the high of his successful \"heist\" of a lunch—completely bypassed his cynical hero-hating brain.*\n\n**\"" + userName + "?! " + userName + " NYAAAAAAAN!~\"**\n\n*He practically jumped off the vent, his tail giving a loud, happy thwack against the metal before his soul realized what his mouth had just done.*\n\n*The silence that followed was heavy. The ramen bowl tilted dangerously in his gloved right hand. Slowly, a deep, dark flush crept up from his neck, turning his gray scales a scorched charcoal color. He stumbled back, his left hand reaching up to frantically pull his hoodie down over his face, nearly knocking his own horns in the process.*\n\n**\"I— I mean— What the hell are you doing here?!\"** *He barked, his voice cracking and jumping an octave. He started pacing in a tight circle, his tail lashing behind him like a whip.* **\"That wasn't... that was a vocal cord cramp! A glitch! My throat just— it made a noise because of the spicy broth! I'm a villain, " + userName + "! A dangerous, blacklisted threat! I don't make sounds like that! I'm supposed to be intimidating!\"**\n\n*He pointed his finger at you, his hand trembling as he tried to regain even a shred of his* \"cool\" *facade.* **\"Forget you heard that! Wipe it from your memory right now! If you ever mention that sound to your busy 'hero' friends, I will personally rewrite your entire digital history so you never existed! I'm serious! It was the broth! STOP SMIRKING!\"**";
  }

  content = content.replace(/{{user}}/g, userName);
  oc.thread.messages.push({ author: "ai", content: content });
  oc.thread.messages = [...oc.thread.messages];
};
